1	import { useEffect, useState } from 'react';
2	import { DataGrid } from '@/shared/components/DataGrid/DataGrid';
3	import { DetailPanel } from '@/shared/components/DetailPanel/DetailPanel';
4	import { SearchForm } from '@/shared/components/SearchForm/SearchForm';
5	import { Input } from '@/shared/components/ui/input';
6	import { getWordById, searchWords } from './wordApi';
7	
8	const columns = [
9	    { key: 'stdWordNm', header: '단어명', sortable: true, width: 220 },
10	    { key: 'stdWordEngAbbrNm', header: '영문약어명', sortable: true, width: 150 },
11	    { key: 'stdWordEngNm', header: '영문명', sortable: true, width: 180 },
12	    { key: 'stdDmnClsfNm', header: '도메인분류명', sortable: true, width: 180 },
13	    { key: 'frmWordYn', header: '형식단어', sortable: false, width: 100, align: 'center' },
14	    { key: 'enctCycl', header: '제정차수', sortable: false, width: 140 },
15	    { key: 'useYn', header: '사용', sortable: false, width: 70, align: 'center' },
16	];
17	
18	const emptyToNull = (value) => {
19	    const next = `${value ?? ''}`.trim();
20	    return next.length ? next : null;
21	};
22	
23	const toSnakeCase = (value) => {
24	    return value.replace(/[A-Z]/g, (match) => `_${match.toLowerCase()}`);
25	};
26	
27	const initialFilters = {
28	    stdWordNm: '',
29	    stdWordEngAbbrNm: '',
30	    stdDmnClsfNm: '',
31	    frmWordYn: '',
32	    useYn: '',
33	};
34	
35	export const WordListPage = () => {
36	    const [filters, setFilters] = useState(initialFilters);
37	    const [request, setRequest] = useState({ page: 1, size: 20 });
38	    const [detailOpen, setDetailOpen] = useState(false);
39	    const [selectedId, setSelectedId] = useState(null);
40	    const [pageData, setPageData] = useState(null);
41	    const [selectedWord, setSelectedWord] = useState(null);
42	
43	    useEffect(() => {
44	        let active = true;
45	
46	        searchWords(request).then((response) => {
47	            if (active) {
48	                setPageData(response);
49	            }
50	        });
51	
52	        return () => {
53	            active = false;
54	        };
55	    }, [request]);
56	
57	    useEffect(() => {
58	        if (selectedId === null || selectedId === undefined) {
59	            return undefined;
60	        }
61	
62	        let active = true;
63	
64	        getWordById(selectedId).then((response) => {
65	            if (active) {
66	                setSelectedWord(response);
67	                setDetailOpen(true);
68	            }
69	        });
70	
71	        return () => {
72	            active = false;
73	        };
74	    }, [selectedId]);
75	
76	    return (
77	        <div className='space-y-6'>
78	            <SearchForm
79	                onSubmit={() => {
80	                    setRequest({
81	                        page: 1,
82	                        size: request.size,
83	                        stdWordNm: emptyToNull(filters.stdWordNm),
84	                        stdWordEngAbbrNm: emptyToNull(filters.stdWordEngAbbrNm),
85	                        stdDmnClsfNm: emptyToNull(filters.stdDmnClsfNm),
86	                        frmWordYn: emptyToNull(filters.frmWordYn),
87	                        useYn: emptyToNull(filters.useYn),
88	                    });
89	                }}
90	                onReset={() => {
91	                    setFilters(initialFilters);
92	                    setRequest({ page: 1, size: request.size });
93	                }}
94	            >
95	                <div className='grid w-full gap-3 md:grid-cols-2 xl:grid-cols-5'>
96	                    <div className='space-y-2'>
97	                        <label className='text-sm font-medium text-slate-700' htmlFor='stdWordNm'>
98	                            단어명
99	                        </label>
100	                        <Input
101	                            id='stdWordNm'
102	                            value={filters.stdWordNm}
103	                            onChange={(event) => setFilters((current) => ({ ...current, stdWordNm: event.target.value }))}
104	                        />
105	                    </div>
106	                    <div className='space-y-2'>
107	                        <label className='text-sm font-medium text-slate-700' htmlFor='stdWordEngAbbrNm'>
108	                            영문약어명
109	                        </label>
110	                        <Input
111	                            id='stdWordEngAbbrNm'
112	                            value={filters.stdWordEngAbbrNm}
113	                            onChange={(event) =>
114	                                setFilters((current) => ({ ...current, stdWordEngAbbrNm: event.target.value }))
115	                            }
116	                        />
117	                    </div>
118	                    <div className='space-y-2'>
119	                        <label className='text-sm font-medium text-slate-700' htmlFor='stdDmnClsfNm'>
120	                            도메인분류명
121	                        </label>
122	                        <Input
123	                            id='stdDmnClsfNm'
124	                            value={filters.stdDmnClsfNm}
125	                            onChange={(event) =>
126	                                setFilters((current) => ({ ...current, stdDmnClsfNm: event.target.value }))
127	                            }
128	                        />
129	                    </div>
130	                    <div className='space-y-2'>
131	                        <label className='text-sm font-medium text-slate-700' htmlFor='frmWordYn'>
132	                            형식단어여부
133	                        </label>
134	                        <select
135	                            id='frmWordYn'
136	                            className='flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm'
137	                            value={filters.frmWordYn}
138	                            onChange={(event) => setFilters((current) => ({ ...current, frmWordYn: event.target.value }))}
139	                        >
140	                            <option value=''>전체</option>
141	                            <option value='Y'>예</option>
142	                            <option value='N'>아니오</option>
143	                        </select>
144	                    </div>
145	                    <div className='space-y-2'>
146	                        <label className='text-sm font-medium text-slate-700' htmlFor='useYn'>
147	                            사용여부
148	                        </label>
149	                        <select
150	                            id='useYn'
151	                            className='flex h-10 w-full rounded-md border border-slate-300 bg-white px-3 py-2 text-sm'
152	                            value={filters.useYn}
153	                            onChange={(event) => setFilters((current) => ({ ...current, useYn: event.target.value }))}
154	                        >
155	                            <option value=''>전체</option>
156	                            <option value='Y'>사용</option>
157	                            <option value='N'>미사용</option>
158	                        </select>
159	                    </div>
160	                </div>
161	            </SearchForm>
162	
163	            <DataGrid
164	                columns={columns}
165	                pageData={pageData}
166	                pageSizeOptions={[10, 20, 50, 100]}
167	                onPageChange={({ page, size }) => setRequest((current) => ({ ...current, page, size }))}
168	                onSortChange={({ active, direction }) =>
169	                    setRequest((current) => ({
170	                        ...current,
171	                        page: 1,
172	                        sortBy: direction ? toSnakeCase(active) : null,
173	                        sortDir: direction || null,
174	                    }))
175	                }
176	                onRowClick={(row) => {
177	                    setSelectedId(row.id);
178	                }}
179	            />
180	
181	            <DetailPanel
182	                position='right'
183	                open={detailOpen}
184	                title={selectedWord?.stdWordNm || '단어 상세'}
185	                onOpenChange={(open) => {
186	                    setDetailOpen(open);
187	                    if (!open) {
188	                        setSelectedId(null);
189	                        setSelectedWord(null);
190	                    }
191	                }}
192	            >
193	                {selectedWord ? (
194	                    <div className='space-y-6 text-sm text-slate-700'>
195	                        <section className='space-y-3'>
196	                            <h3 className='text-base font-semibold text-slate-900'>기본 정보</h3>
197	                            <dl className='grid gap-x-4 gap-y-2 md:grid-cols-[140px_1fr]'>
198	                                <dt>ID</dt>
199	                                <dd>{selectedWord.id}</dd>
200	                                <dt>단어명</dt>
201	                                <dd>{selectedWord.stdWordNm}</dd>
202	                                <dt>영문약어명</dt>
203	                                <dd>{selectedWord.stdWordEngAbbrNm || '-'}</dd>
204	                                <dt>영문명</dt>
205	                                <dd>{selectedWord.stdWordEngNm || '-'}</dd>
206	                                <dt>설명</dt>
207	                                <dd>{selectedWord.stdWordExpln || '-'}</dd>
208	                                <dt>형식단어여부</dt>
209	                                <dd>{selectedWord.frmWordYn || '-'}</dd>
210	                                <dt>도메인분류명</dt>
211	                                <dd>{selectedWord.stdDmnClsfNm || '-'}</dd>
212	                                <dt>이음동의어 목록</dt>
213	                                <dd>{selectedWord.synmListCn || '-'}</dd>
214	                                <dt>금칙어 목록</dt>
215	                                <dd>{selectedWord.phwrdListCn || '-'}</dd>
216	                                <dt>제정차수</dt>
217	                                <dd>{selectedWord.enctCycl || '-'}</dd>
218	                                <dt>개정구분명</dt>
219	                                <dd>{selectedWord.rvsnSeNm || '-'}</dd>
220	                                <dt>개정항목</dt>
221	                                <dd>{selectedWord.rvsnArtclNm || '-'}</dd>
222	                                <dt>개정사유</dt>
223	                                <dd>{selectedWord.rvsnRsn || '-'}</dd>
224	                                <dt>사용여부</dt>
225	                                <dd>{selectedWord.useYn || '-'}</dd>
226	                            </dl>
227	                        </section>
228	                    </div>
229	                ) : null}
230	            </DetailPanel>
231	        </div>
232	    );
233	}
