1	import { zodResolver } from '@hookform/resolvers/zod';
2	import { useMutation } from '@tanstack/react-query';
3	import { useForm } from 'react-hook-form';
4	import { useNavigate, useSearchParams } from 'react-router-dom';
5	import { Button } from '@/shared/components/ui/button';
6	import { Input } from '@/shared/components/ui/input';
7	import { useAuthStore } from '@/store/useAuthStore';
8	import { login } from './authApi';
9	import { loginSchema } from './login.schema';
10	
11	export const LoginPage = () => {
12	    const navigate = useNavigate();
13	    const [searchParams] = useSearchParams();
14	    const setUser = useAuthStore((state) => state.setUser);
15	    const returnUrl = searchParams.get('returnUrl') || '/home';
16	    const {
17	        register,
18	        handleSubmit,
19	        formState: { errors },
20	    } = useForm({
21	        resolver: zodResolver(loginSchema),
22	        defaultValues: {
23	            username: '',
24	            password: '',
25	        },
26	    });
27	
28	    const mutation = useMutation({
29	        mutationFn: login,
30	        onSuccess: (data) => {
31	            setUser(data.user);
32	            navigate(returnUrl, { replace: true });
33	        },
34	    });
35	
36	    return (
37	        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60'>
38	            <header className='mb-6 space-y-2'>
39	                <h1 className='text-2xl font-semibold text-slate-900'>TrmWordDict</h1>
40	                <p className='text-sm text-slate-500'>행정 용어 사전 시스템</p>
41	            </header>
42	            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
43	                <div className='space-y-2'>
44	                    <label className='text-sm font-medium text-slate-700' htmlFor='username'>
45	                        아이디
46	                    </label>
47	                    <Input id='username' autoComplete='username' {...register('username')} />
48	                    {errors.username ? <p className='text-sm text-rose-600'>{errors.username.message}</p> : null}
49	                </div>
50	                <div className='space-y-2'>
51	                    <label className='text-sm font-medium text-slate-700' htmlFor='password'>
52	                        비밀번호
53	                    </label>
54	                    <Input id='password' type='password' autoComplete='current-password' {...register('password')} />
55	                    {errors.password ? <p className='text-sm text-rose-600'>{errors.password.message}</p> : null}
56	                </div>
57	                {mutation.isError ? <p className='text-sm text-rose-600'>로그인에 실패했습니다.</p> : null}
58	                <Button className='w-full' type='submit' disabled={mutation.isPending}>
59	                    로그인
60	                </Button>
61	            </form>
62	        </section>
63	    );
64	}
