1	import { useMutation } from '@tanstack/react-query';
2	import { useState } from 'react';
3	import { useNavigate } from 'react-router-dom';
4	import { Button } from '@/shared/components/ui/button';
5	import { FileUpload } from '@/shared/components/FileUpload/FileUpload';
6	import { uploadCsv } from './importApi';
7	import { IMPORT_TYPE_OPTIONS } from './import.model';
8	
9	export const UploadPage = () => {
10	    const navigate = useNavigate();
11	    const [type, setType] = useState('word');
12	    const [file, setFile] = useState(null);
13	    const [error, setError] = useState('');
14	
15	    const mutation = useMutation({
16	        mutationFn: ({ nextType, nextFile }) => uploadCsv(nextType, nextFile),
17	        onSuccess: ({ historyId }) => {
18	            navigate(`/import/${historyId}`);
19	        },
20	    });
21	
22	    const submit = () => {
23	        if (!file) {
24	            setError('CSV 파일을 선택하세요.');
25	            return;
26	        }
27	
28	        setError('');
29	        mutation.mutate({ nextType: type, nextFile: file });
30	    };
31	
32	    return (
33	        <section className='space-y-5 rounded-2xl border border-slate-200 bg-white p-8 shadow-sm'>
34	            <header className='space-y-2'>
35	                <h2 className='text-2xl font-semibold text-slate-900'>데이터 가져오기</h2>
36	                <p className='text-sm text-slate-600'>
37	                    행정표준 공통서식 CSV를 업로드합니다. 헤더와 서식은 서버 기준과 일치해야 합니다.
38	                </p>
39	            </header>
40	
41	            <fieldset className='space-y-3'>
42	                <legend className='text-sm font-medium text-slate-700'>가져올 유형 선택</legend>
43	                <div className='flex flex-wrap gap-3'>
44	                    {IMPORT_TYPE_OPTIONS.map((option) => (
45	                        <label
46	                            key={option.value}
47	                            className='inline-flex items-center gap-2 rounded-full border border-slate-300 px-4 py-2 text-sm'
48	                        >
49	                            <input
50	                                type='radio'
51	                                name='importType'
52	                                aria-label={`가져올 유형 ${option.value}`}
53	                                checked={type === option.value}
54	                                onChange={() => setType(option.value)}
55	                            />
56	                            <span>{option.label}</span>
57	                        </label>
58	                    ))}
59	                </div>
60	            </fieldset>
61	
62	            <FileUpload
63	                accept='.csv'
64	                maxSizeMB={50}
65	                label='CSV 파일 선택'
66	                onFileSelected={(nextFile) => {
67	                    setFile(nextFile);
68	                    setError('');
69	                }}
70	                onFileRejected={() => {
71	                    setFile(null);
72	                }}
73	            />
74	
75	            {file ? <p className='text-sm text-slate-600'>선택 파일: {file.name}</p> : null}
76	            {error ? <p className='text-sm text-rose-600'>{error}</p> : null}
77	            {mutation.isError ? <p className='text-sm text-rose-600'>업로드에 실패했습니다.</p> : null}
78	
79	            <div className='flex justify-end'>
80	                <Button onClick={submit} disabled={mutation.isPending}>
81	                    {mutation.isPending ? '업로드 중..' : '업로드'}
82	                </Button>
83	            </div>
84	        </section>
85	    );
86	}
