1	import axios from 'axios';
2	import { useAuthStore } from '../../store/useAuthStore';
3	
4	export const axiosInstance = axios.create({
5	    baseURL: '/api/v1',
6	    timeout: 30000,
7	    withCredentials: true,
8	    headers: {
9	        'Content-Type': 'application/json',
10	    },
11	});
12	
13	axiosInstance.interceptors.response.use(
14	    (response) => response,
15	    (error) => {
16	        const status = error.response?.status;
17	        const code = error.response?.data?.code;
18	
19	        if (status === 401 || code === 'AUTH_1002') {
20	            axios.post('/api/v1/auth/logout', null, { withCredentials: true }).catch(() => {});
21	            useAuthStore.getState().logout();
22	        }
23	
24	        return Promise.reject(error);
25	    }
26	);
27	
28	export const unwrapResponse = (response) => {
29	    if (!response.data?.success || response.data?.data === null || response.data?.data === undefined) {
30	        throw new Error(response.data?.message ?? '요청 처리에 실패했습니다.');
31	    }
32	    return response.data.data;
33	};
