30	            onFileRejected?.({
31	                reason: 'SIZE',
32	                message: `파일 크기가 ${maxSizeMB}MB를 초과했습니다.`,
33	            });
34	            return;
35	        }
36	
37	        onFileSelected?.(file);
38	    };
39	
40	    return (
41	        <label className='inline-flex cursor-pointer items-center gap-2'>
42	            <input
43	                type='file'
44	                aria-label={label}
45	                className='sr-only'
46	                onChange={(event) => {
47	                    const file = event.target.files?.[0];
48	
49	                    if (file) {
50	                        handleFile(file);
51	                    }
52	
53	                    event.target.value = '';
54	                }}
55	            />
56	            <Button variant='outline'>
57	                <Upload className='h-4 w-4' />
58	                <span>{label}</span>
59	            </Button>
60	        </label>
61	    );
